/* CompTIA AI Fundamentals :: content/quiz6.js — question bank for Domain 6 (100 items). */
window.AIFUND = window.AIFUND || {}; AIFUND.questions = AIFUND.questions || [];
AIFUND.questions.push(
{ id:"D6-001", domain:6, obj:"6.1", diff:"easy", q:"Which everyday task is BEST suited for AI automation?", options:["Deciding whether to lay off a specific employee","Signing a legally binding contract on the company's behalf","Drafting a first version of a routine status email from bullet points","Approving a customer's insurance claim with no review"], answer:2, explain:"<strong>Drafting a first version of a routine status email from bullet points</strong> is repetitive, low-risk, and easy for a human to review, which makes it an ideal candidate for AI assistance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deciding whether to lay off a specific employee</b>: this is a high-stakes human judgment involving fairness and law, not something to hand to an automated tool.</span><span class='qd'><b>Signing a legally binding contract on the company's behalf</b>: legal commitment requires accountable human authority, so it should not be automated.</span><span class='qd'><b>Approving a customer's insurance claim with no review</b>: consequential decisions affecting people's money need human oversight, so \"no review\" is inappropriate.</span>" },
{ id:"D6-002", domain:6, obj:"6.1", diff:"easy", q:"An AI writing assistant is MOST helpful for which of the following?", options:["Guaranteeing every fact in a document is correct","Serving as the sole approver of financial statements","Summarizing a long report into key bullet points for review","Making the final hiring decision for a role"], answer:2, explain:"<strong>Summarizing a long report into key bullet points for review</strong> plays to AI's strength at condensing text quickly while leaving the human to verify the result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteeing every fact in a document is correct</b>: AI can generate confident but wrong statements, so it cannot guarantee factual accuracy.</span><span class='qd'><b>Serving as the sole approver of financial statements</b>: sign-off on financials is an accountable human control, not an AI task.</span><span class='qd'><b>Making the final hiring decision for a role</b>: hiring is a consequential judgment that must stay with a person.</span>" },
{ id:"D6-003", domain:6, obj:"6.1", diff:"easy", q:"Which characteristic makes a task a GOOD fit for AI automation?", options:["It requires rare ethical judgment with legal consequences","It has no correct answer and depends entirely on emotion","It must be kept secret from everyone including the operator","It is repetitive, well-defined, and easy for a human to check"], answer:3, explain:"A task that is <strong>It is repetitive, well-defined, and easy for a human to check</strong> lets AI save time while a person can quickly confirm the output is right.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It requires rare ethical judgment with legal consequences</b>: high-stakes ethical calls should remain with accountable humans.</span><span class='qd'><b>It has no correct answer and depends entirely on emotion</b>: purely emotional, subjective tasks are poor fits because there is nothing to verify.</span><span class='qd'><b>It must be kept secret from everyone including the operator</b>: secrecy from the operator is a data-handling concern, not a reason a task suits automation.</span>" },
{ id:"D6-004", domain:6, obj:"6.1", diff:"easy", q:"A marketing coordinator wants ten alternative headlines for an ad. Why is this a good use of a generative AI tool?", options:["The AI legally owns and approves the final headline","The AI will confirm the sales numbers are accurate","The task removes the need for any human review","Generating many quick variations for a human to choose from is a strength of AI"], answer:3, explain:"<strong>Generating many quick variations for a human to choose from is a strength of AI</strong> because brainstorming volume is fast for the model while the human still picks the best option.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI legally owns and approves the final headline</b>: the AI has no legal authority; the human coordinator remains responsible.</span><span class='qd'><b>The AI will confirm the sales numbers are accurate</b>: generating headlines has nothing to do with verifying figures.</span><span class='qd'><b>The task removes the need for any human review</b>: a person still needs to choose and check the headline, so review is not removed.</span>" },
{ id:"D6-005", domain:6, obj:"6.1", diff:"easy", q:"Which of these is LEAST appropriate to fully automate with AI and no human check?", options:["Suggesting synonyms while a person writes","Reformatting a list of names into a table","Generating draft social-media captions for later review","Deciding which patients receive a medical treatment"], answer:3, explain:"<strong>Deciding which patients receive a medical treatment</strong> is a life-affecting decision that demands qualified human judgment and accountability, so it must not be fully automated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Suggesting synonyms while a person writes</b>: this is a low-risk aid where the human stays in control of the wording.</span><span class='qd'><b>Reformatting a list of names into a table</b>: formatting is mechanical and easy to verify, making it low risk.</span><span class='qd'><b>Generating draft social-media captions for later review</b>: drafts explicitly kept for later review keep a human in the loop.</span>" },
{ id:"D6-006", domain:6, obj:"6.1", diff:"medium", q:"A team lead asks whether to use AI to \"decide employee bonuses automatically.\" What is the BEST response?", options:["Yes, because AI is always more objective than people","No, because bonus decisions are consequential and need human accountability and oversight","Yes, because it removes the need to document anything","No, because AI cannot read numbers at all"], answer:1, explain:"<strong>No, because bonus decisions are consequential and need human accountability and oversight</strong> correctly recognizes that pay decisions affect livelihoods and fairness, so a person must own them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Yes, because AI is always more objective than people</b>: AI can inherit bias from its data and is not automatically objective.</span><span class='qd'><b>Yes, because it removes the need to document anything</b>: automating a decision does not remove the need for documentation and can increase it.</span><span class='qd'><b>No, because AI cannot read numbers at all</b>: AI can process numbers; the real reason to keep humans involved is accountability, not incapacity.</span>" },
{ id:"D6-007", domain:6, obj:"6.1", diff:"medium", q:"Which pair of factors is MOST useful when deciding whether to automate a task with AI?", options:["The color of the interface and the vendor's logo","The task's risk level and how easily a human can verify the output","The number of words in the prompt and the time of day","Whether the tool is free and how many people have heard of it"], answer:1, explain:"<strong>The task's risk level and how easily a human can verify the output</strong> are the core factors: low risk plus easy verification favors automation, while high risk favors keeping humans in control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color of the interface and the vendor's logo</b>: cosmetic details have no bearing on whether a task should be automated.</span><span class='qd'><b>The number of words in the prompt and the time of day</b>: these are irrelevant to the suitability or risk of the task.</span><span class='qd'><b>Whether the tool is free and how many people have heard of it</b>: popularity and price do not determine whether a task is safe to automate.</span>" },
{ id:"D6-008", domain:6, obj:"6.1", diff:"medium", q:"An accountant considers using AI to categorize hundreds of routine receipts, then spot-check the results. Why is this reasonable?", options:["Because AI results never need any checking","Because the task is repetitive and the human still verifies a sample","Because it makes the accountant legally unnecessary","Because AI is guaranteed to be 100 percent accurate on receipts"], answer:1, explain:"<strong>Because the task is repetitive and the human still verifies a sample</strong> captures a sound approach: AI handles the volume while spot-checking keeps a human in the loop to catch errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI results never need any checking</b>: AI can misclassify, so results do need checking, which is exactly why spot-checks are used.</span><span class='qd'><b>Because it makes the accountant legally unnecessary</b>: the accountant remains responsible for the books; AI does not remove accountability.</span><span class='qd'><b>Because AI is guaranteed to be 100 percent accurate on receipts</b>: no AI tool is guaranteed perfectly accurate, so verification is still needed.</span>" },
{ id:"D6-009", domain:6, obj:"6.1", diff:"medium", q:"Which scenario shows AI being used for a task it is POORLY suited to on its own?", options:["Providing definitive legal advice a client will act on without a lawyer","Suggesting a subject line for a newsletter","Rewriting a paragraph to be more concise","Brainstorming names for a new product"], answer:0, explain:"<strong>Providing definitive legal advice a client will act on without a lawyer</strong> is poorly suited to AI alone because errors carry legal consequences and a qualified professional must be involved.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Suggesting a subject line for a newsletter</b>: this is low-risk creative help that a person can easily accept or reject.</span><span class='qd'><b>Rewriting a paragraph to be more concise</b>: editing text is a well-suited, easily reviewed task.</span><span class='qd'><b>Brainstorming names for a new product</b>: idea generation is a strength of AI with the human choosing the final name.</span>" },
{ id:"D6-010", domain:6, obj:"6.1", diff:"medium", q:"A support team wants AI to draft replies to common customer questions. What is the MOST responsible way to deploy this?", options:["Have agents review and edit AI drafts before sending","Send AI replies to customers automatically with no human review","Replace the entire support team immediately","Use the AI only to delete customer messages"], answer:0, explain:"<strong>Have agents review and edit AI drafts before sending</strong> keeps a human in the loop so mistakes are caught while still saving drafting time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send AI replies to customers automatically with no human review</b>: unreviewed replies risk sending wrong or inappropriate information to customers.</span><span class='qd'><b>Replace the entire support team immediately</b>: eliminating oversight removes the verification that keeps quality and trust.</span><span class='qd'><b>Use the AI only to delete customer messages</b>: deleting messages is not the goal and would harm customers.</span>" },
{ id:"D6-011", domain:6, obj:"6.1", diff:"medium", q:"Why might repetitive, high-volume text tasks be especially good candidates for AI support?", options:["Because AI can produce drafts quickly and free people for higher-judgment work","Because AI eliminates the need to ever check quality","Because volume tasks are always the most important work","Because AI can only work on large tasks"], answer:0, explain:"<strong>Because AI can produce drafts quickly and free people for higher-judgment work</strong> explains the real benefit: automating routine volume lets humans focus their attention where judgment matters most.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI eliminates the need to ever check quality</b>: quality checks remain necessary since AI can still make mistakes.</span><span class='qd'><b>Because volume tasks are always the most important work</b>: high volume does not mean high importance; often the opposite.</span><span class='qd'><b>Because AI can only work on large tasks</b>: AI handles small tasks too, so this is simply false.</span>" },
{ id:"D6-012", domain:6, obj:"6.1", diff:"medium", q:"A manager says, \"Let's automate our final quality-control sign-off with AI so no one has to look at it.\" What is the key concern?", options:["The AI will be too slow to keep up","The AI will refuse to do quality control","Removing all human review from a final sign-off eliminates accountability for errors","There is no concern; final sign-offs should always be fully automated"], answer:2, explain:"<strong>Removing all human review from a final sign-off eliminates accountability for errors</strong> is the central concern: a final approval is a control point that needs a responsible human.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will be too slow to keep up</b>: speed is not the issue; oversight and responsibility are.</span><span class='qd'><b>The AI will refuse to do quality control</b>: the tool may perform the task, but that does not make it wise to remove human sign-off.</span><span class='qd'><b>There is no concern; final sign-offs should always be fully automated</b>: final sign-offs are exactly where human accountability is most important.</span>" },
{ id:"D6-013", domain:6, obj:"6.1", diff:"medium", q:"Which task is the STRONGEST candidate for AI automation in a small business?", options:["Choosing which employee to promote","Turning meeting notes into a tidy summary a manager will review","Deciding the company's annual strategy alone","Approving large payments without oversight"], answer:1, explain:"<strong>Turning meeting notes into a tidy summary a manager will review</strong> is repetitive, low-risk, and reviewed by a human, making it an excellent automation candidate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choosing which employee to promote</b>: promotion decisions are consequential judgments that belong to people.</span><span class='qd'><b>Deciding the company's annual strategy alone</b>: strategy is a high-stakes leadership responsibility, not an AI-only task.</span><span class='qd'><b>Approving large payments without oversight</b>: unsupervised payment approval is a financial control that must involve humans.</span>" },
{ id:"D6-014", domain:6, obj:"6.1", diff:"hard", q:"A hospital wants to speed up work with AI. Which use keeps AI in an appropriate supporting role rather than an unsafe one?", options:["AI makes the final diagnosis and no clinician reviews it","AI decides medication doses and administers them automatically","AI drafts a summary of a patient's chart for a clinician to verify","AI approves surgeries without any doctor involved"], answer:2, explain:"<strong>AI drafts a summary of a patient's chart for a clinician to verify</strong> keeps AI as a time-saving assistant while a qualified human makes the medical judgment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI makes the final diagnosis and no clinician reviews it</b>: an unreviewed final diagnosis removes the essential human medical judgment.</span><span class='qd'><b>AI decides medication doses and administers them automatically</b>: automated dosing without oversight is unsafe for a life-critical task.</span><span class='qd'><b>AI approves surgeries without any doctor involved</b>: surgical approval must involve accountable clinicians, not automation alone.</span>" },
{ id:"D6-015", domain:6, obj:"6.1", diff:"hard", q:"An operations lead must choose ONE process to pilot with AI. Which choice BEST balances benefit and safety?", options:["Automating final legal contract approval end to end","Auto-sending refunds of any amount with no checks","Letting AI unilaterally change customer account balances","Drafting internal FAQ answers that staff edit before publishing"], answer:3, explain:"<strong>Drafting internal FAQ answers that staff edit before publishing</strong> offers real time savings on a routine task while a human review step contains the risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Automating final legal contract approval end to end</b>: legal approval carries binding consequences that require human authority.</span><span class='qd'><b>Auto-sending refunds of any amount with no checks</b>: unchecked financial payouts invite costly errors and abuse.</span><span class='qd'><b>Letting AI unilaterally change customer account balances</b>: unsupervised changes to balances are high-risk and need controls.</span>" },
{ id:"D6-016", domain:6, obj:"6.1", diff:"hard", q:"A department wants to measure whether automating a task with AI is worthwhile. Which approach is MOST sound?", options:["Assume any automation saves money and skip measurement","Compare time saved and error rates against the cost of review and mistakes","Automate everything first, then never look back","Choose based only on which competitor uses the most AI"], answer:1, explain:"<strong>Compare time saved and error rates against the cost of review and mistakes</strong> is sound because it weighs the real benefits against the real costs, including the effort of checking AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume any automation saves money and skip measurement</b>: automation can add review cost or errors, so assuming savings is risky.</span><span class='qd'><b>Automate everything first, then never look back</b>: failing to review outcomes can let hidden problems grow.</span><span class='qd'><b>Choose based only on which competitor uses the most AI</b>: copying competitors ignores your own task's risk and value.</span>" },
{ id:"D6-017", domain:6, obj:"6.1", diff:"hard", q:"Which statement BEST reflects a mature view of AI automation in the workplace?", options:["AI is best at augmenting people on suitable tasks while humans own high-stakes decisions","AI should replace human judgment wherever possible to cut costs","AI removes the need for any human accountability","AI should only ever be used for tasks no human understands"], answer:0, explain:"<strong>AI is best at augmenting people on suitable tasks while humans own high-stakes decisions</strong> reflects the balanced, widely accepted view that AI amplifies human work rather than replacing responsibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI should replace human judgment wherever possible to cut costs</b>: replacing judgment to save money ignores risk and accountability.</span><span class='qd'><b>AI removes the need for any human accountability</b>: accountability always stays with people, regardless of tooling.</span><span class='qd'><b>AI should only ever be used for tasks no human understands</b>: using AI on tasks no one understands makes verification impossible and is unsafe.</span>" },
{ id:"D6-018", domain:6, obj:"6.1", diff:"medium", q:"A recruiter wants AI to write personalized outreach messages to candidates. Which practice is MOST responsible?", options:["Review and personalize each draft, then send it yourself","Send every AI message unread to save time","Let AI schedule interviews and reject candidates automatically","Use AI to fabricate details about the company to attract candidates"], answer:0, explain:"<strong>Review and personalize each draft, then send it yourself</strong> keeps a human owning the message while still benefiting from AI's speed at drafting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send every AI message unread to save time</b>: unread messages risk errors or tone problems reaching candidates.</span><span class='qd'><b>Let AI schedule interviews and reject candidates automatically</b>: rejecting candidates is a consequential decision needing human judgment.</span><span class='qd'><b>Use AI to fabricate details about the company to attract candidates</b>: fabricating facts is dishonest and damages trust.</span>" },
{ id:"D6-019", domain:6, obj:"6.1", diff:"easy", q:"Which is an appropriate low-risk task to hand to an AI assistant?", options:["Deciding who gets fired","Signing your tax return for you","Choosing the company's new CEO","Converting a paragraph into a bulleted list"], answer:3, explain:"<strong>Converting a paragraph into a bulleted list</strong> is a simple, low-stakes formatting task that a person can instantly verify.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deciding who gets fired</b>: termination is a serious human decision, not an AI task.</span><span class='qd'><b>Signing your tax return for you</b>: signing a legal document requires accountable human authority.</span><span class='qd'><b>Choosing the company's new CEO</b>: executive selection is a major governance decision for people, not automation.</span>" },
{ id:"D6-020", domain:6, obj:"6.1", diff:"medium", q:"A teacher wants to use AI to grade essays. What is the MOST appropriate approach?", options:["Let AI assign final grades with no review","Publish AI grades to students automatically","Have AI decide which students pass the course alone","Use AI to suggest feedback that the teacher reviews and adjusts"], answer:3, explain:"<strong>Use AI to suggest feedback that the teacher reviews and adjusts</strong> keeps the educator's judgment central while using AI to save time on drafting comments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let AI assign final grades with no review</b>: final grades affect students significantly and need teacher oversight.</span><span class='qd'><b>Publish AI grades to students automatically</b>: publishing unreviewed grades risks unfair or wrong marks.</span><span class='qd'><b>Have AI decide which students pass the course alone</b>: pass/fail decisions are consequential and belong to the teacher.</span>" },
{ id:"D6-021", domain:6, obj:"6.2", diff:"easy", q:"Which of the following BEST describes a common \"draft-then-refine\" AI workflow?", options:["Ask AI for a first draft, then edit and improve it yourself","Publish the AI's first answer without reading it","Ask the same question ten times and average the answers","Refuse to give the AI any instructions"], answer:0, explain:"<strong>Ask AI for a first draft, then edit and improve it yourself</strong> is the classic draft-then-refine pattern where AI accelerates the start and the human polishes the result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish the AI's first answer without reading it</b>: skipping review defeats the refine step and risks errors.</span><span class='qd'><b>Ask the same question ten times and average the answers</b>: averaging identical questions is not a refinement workflow and wastes effort.</span><span class='qd'><b>Refuse to give the AI any instructions</b>: withholding instructions prevents a useful draft in the first place.</span>" },
{ id:"D6-022", domain:6, obj:"6.2", diff:"easy", q:"In a \"summarize-then-review\" workflow, what is the human's main job?", options:["To read the AI summary and confirm it is accurate and complete","To generate the original long document from scratch","To delete the source material immediately","To translate the summary into code"], answer:0, explain:"<strong>To read the AI summary and confirm it is accurate and complete</strong> is the human's role, since the value of the workflow depends on verifying the condensed version.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To generate the original long document from scratch</b>: the source already exists; the human reviews the summary, not writes the original.</span><span class='qd'><b>To delete the source material immediately</b>: deleting the source removes the ability to check the summary.</span><span class='qd'><b>To translate the summary into code</b>: turning a summary into code is unrelated to reviewing it.</span>" },
{ id:"D6-023", domain:6, obj:"6.2", diff:"easy", q:"A user asks AI to draft an email, then follows up with \"make it shorter and more formal.\" This back-and-forth is an example of:", options:["A one-shot final answer","Ignoring the AI's output","Iterative refinement through follow-up prompts","Encrypting the conversation"], answer:2, explain:"<strong>Iterative refinement through follow-up prompts</strong> describes steering the output step by step, which is a core AI workflow pattern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-shot final answer</b>: a one-shot answer involves no follow-up, which is the opposite of what happened.</span><span class='qd'><b>Ignoring the AI's output</b>: the user is actively refining the output, not ignoring it.</span><span class='qd'><b>Encrypting the conversation</b>: encryption is a security concept unrelated to refining a draft.</span>" },
{ id:"D6-024", domain:6, obj:"6.2", diff:"easy", q:"Which is an example of an \"extract-and-organize\" AI workflow?", options:["Asking AI to invent fake data for a report","Telling AI to never follow instructions","Deleting a spreadsheet to save space","Pasting messy notes and asking AI to pull out action items into a table"], answer:3, explain:"<strong>Pasting messy notes and asking AI to pull out action items into a table</strong> is a classic extract-and-organize pattern, turning unstructured input into structured output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking AI to invent fake data for a report</b>: fabricating data is dishonest and not a legitimate workflow.</span><span class='qd'><b>Telling AI to never follow instructions</b>: this prevents any useful work rather than describing a workflow.</span><span class='qd'><b>Deleting a spreadsheet to save space</b>: deleting a file is unrelated to extracting and organizing information.</span>" },
{ id:"D6-025", domain:6, obj:"6.2", diff:"easy", q:"What does a \"generate-and-select\" workflow look like in practice?", options:["Accept the first option no matter what","Ask AI to choose your options and never look","Reject all options and start over each time","Ask AI for several options, then pick the best one yourself"], answer:3, explain:"<strong>Ask AI for several options, then pick the best one yourself</strong> is the generate-and-select pattern, using AI for volume while the human exercises judgment in choosing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the first option no matter what</b>: accepting the first option skips the selection step that gives the pattern its value.</span><span class='qd'><b>Ask AI to choose your options and never look</b>: letting AI choose with no review removes human judgment.</span><span class='qd'><b>Reject all options and start over each time</b>: perpetually restarting is not selecting and wastes effort.</span>" },
{ id:"D6-026", domain:6, obj:"6.2", diff:"medium", q:"A analyst pastes a long article and asks AI to \"list the three main arguments.\" Which workflow pattern is this?", options:["Image generation","Summarization/extraction","Real-time translation of speech","Password recovery"], answer:1, explain:"<strong>Summarization/extraction</strong> is the pattern, because the task condenses a large text down to its key points.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Image generation</b>: no image is being created; the task works with text.</span><span class='qd'><b>Real-time translation of speech</b>: nothing is being translated or spoken here.</span><span class='qd'><b>Password recovery</b>: recovering a password is unrelated to summarizing an article.</span>" },
{ id:"D6-027", domain:6, obj:"6.2", diff:"medium", q:"Why is it often better to build a document with AI in stages (outline, then sections, then polish) rather than one giant prompt?", options:["Because AI can only read short prompts","Because staged work is easier to steer and review at each step","Because outlines are illegal to skip","Because one giant prompt always crashes the tool"], answer:1, explain:"<strong>Because staged work is easier to steer and review at each step</strong> is the practical reason: breaking work into stages lets the human guide and check progress along the way.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI can only read short prompts</b>: modern tools can handle long prompts, so this is not the reason.</span><span class='qd'><b>Because outlines are illegal to skip</b>: there is no law about outlines; this is a productivity choice.</span><span class='qd'><b>Because one giant prompt always crashes the tool</b>: a long prompt does not always crash anything; the benefit is control and review.</span>" },
{ id:"D6-028", domain:6, obj:"6.2", diff:"medium", q:"A user asks AI to draft a policy, then asks a colleague to fact-check it before publishing. The fact-check step is BEST described as:", options:["An unnecessary delay that should be removed","The AI generating the policy","A verification step in the workflow","A way to hide that AI was used"], answer:2, explain:"<strong>A verification step in the workflow</strong> correctly labels the colleague's fact-check, which is an essential quality control on AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An unnecessary delay that should be removed</b>: verification is valuable, not a delay to cut, especially for a policy.</span><span class='qd'><b>The AI generating the policy</b>: the AI already drafted it; the colleague is checking, not generating.</span><span class='qd'><b>A way to hide that AI was used</b>: fact-checking has nothing to do with concealing AI use.</span>" },
{ id:"D6-029", domain:6, obj:"6.2", diff:"medium", q:"Which describes a sensible \"translate-then-review\" workflow for a non-native speaker?", options:["Publish the translation without any check because AI is always right","Use AI to translate a message, then have a fluent colleague confirm the meaning","Refuse to use translation tools entirely","Translate the message ten times and pick a random result"], answer:1, explain:"<strong>Use AI to translate a message, then have a fluent colleague confirm the meaning</strong> pairs AI speed with a human check to catch subtle errors of tone or meaning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish the translation without any check because AI is always right</b>: AI translations can miss nuance, so a check is wise.</span><span class='qd'><b>Refuse to use translation tools entirely</b>: refusing the tool discards a legitimate, helpful workflow.</span><span class='qd'><b>Translate the message ten times and pick a random result</b>: random selection is not a review and offers no quality assurance.</span>" },
{ id:"D6-030", domain:6, obj:"6.2", diff:"medium", q:"A team uses AI to draft, a peer to edit, and a manager to approve before anything ships. This is an example of:", options:["A multi-step human review workflow around AI output","Fully autonomous AI with no oversight","A workflow that hides mistakes from everyone","A method to avoid ever publishing anything"], answer:0, explain:"<strong>A multi-step human review workflow around AI output</strong> describes layered checks that improve quality and accountability while still using AI to start the work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fully autonomous AI with no oversight</b>: the presence of a peer editor and manager approval is the opposite of no oversight.</span><span class='qd'><b>A workflow that hides mistakes from everyone</b>: multiple reviewers make mistakes more likely to be caught, not hidden.</span><span class='qd'><b>A method to avoid ever publishing anything</b>: the workflow leads to shipping approved work, not blocking it.</span>" },
{ id:"D6-031", domain:6, obj:"6.2", diff:"medium", q:"When using AI to help write code or a spreadsheet formula, why is testing the result an important workflow step?", options:["Because AI output can look correct but still contain errors","Because testing makes the code run faster automatically","Because AI never produces working output","Because testing removes the need to understand the task"], answer:0, explain:"<strong>Because AI output can look correct but still contain errors</strong> is why testing matters: plausible-looking results can still be wrong, so verification catches problems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because testing makes the code run faster automatically</b>: testing checks correctness; it does not speed up execution by itself.</span><span class='qd'><b>Because AI never produces working output</b>: AI often produces working output, but not always, which is exactly why you test.</span><span class='qd'><b>Because testing removes the need to understand the task</b>: understanding the task is still required to judge the results.</span>" },
{ id:"D6-032", domain:6, obj:"6.2", diff:"medium", q:"A user gives AI an example of the format they want and asks it to match that format. This technique is BEST known as:", options:["Providing an example (few-shot) to guide the output","Deleting the conversation history","Encrypting the prompt","Turning off the internet"], answer:0, explain:"<strong>Providing an example (few-shot) to guide the output</strong> describes giving the model a sample so it mirrors the desired structure, a common and effective workflow technique.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting the conversation history</b>: clearing history does not guide formatting.</span><span class='qd'><b>Encrypting the prompt</b>: encryption is a security action unrelated to shaping output.</span><span class='qd'><b>Turning off the internet</b>: disconnecting does not influence how the AI formats a response.</span>" },
{ id:"D6-033", domain:6, obj:"6.2", diff:"hard", q:"A content team wants a repeatable workflow to turn interview recordings into blog posts. Which sequence is MOST sound?", options:["Draft the post first, then record an interview to match it","Publish the raw transcript with no editing as the final post","Transcribe, summarize key points, draft with AI, then human edit and fact-check","Skip the recording and have AI invent the interview"], answer:2, explain:"<strong>Transcribe, summarize key points, draft with AI, then human edit and fact-check</strong> is a logical, repeatable pipeline that ends with human verification before publishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Draft the post first, then record an interview to match it</b>: reversing the order fabricates the basis of the post.</span><span class='qd'><b>Publish the raw transcript with no editing as the final post</b>: an unedited transcript is rarely publishable and skips quality control.</span><span class='qd'><b>Skip the recording and have AI invent the interview</b>: inventing an interview is dishonest and produces fabricated content.</span>" },
{ id:"D6-034", domain:6, obj:"6.2", diff:"hard", q:"An analyst wants AI to help analyze survey comments but is worried about accuracy. Which workflow BEST manages that risk?", options:["Have AI cluster themes, then manually verify a sample of comments in each theme","Trust the AI's theme labels completely and report them as final","Ask AI to make up representative quotes to save time","Delete comments the AI finds hard to categorize"], answer:0, explain:"<strong>Have AI cluster themes, then manually verify a sample of comments in each theme</strong> combines AI's speed with human spot-checking, directly addressing the accuracy concern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI's theme labels completely and report them as final</b>: trusting labels blindly ignores the stated accuracy risk.</span><span class='qd'><b>Ask AI to make up representative quotes to save time</b>: fabricating quotes misrepresents real respondents.</span><span class='qd'><b>Delete comments the AI finds hard to categorize</b>: discarding hard cases biases the analysis and hides information.</span>" },
{ id:"D6-035", domain:6, obj:"6.2", diff:"hard", q:"A team notices their AI-assisted report contained a fabricated citation. What is the BEST workflow change to prevent recurrence?", options:["Stop reading the reports so no one notices","Add a mandatory step to verify every citation against a real source before publishing","Tell AI to add more citations next time","Remove all citations from every report permanently"], answer:1, explain:"<strong>Add a mandatory step to verify every citation against a real source before publishing</strong> directly targets the root cause by requiring human confirmation of sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stop reading the reports so no one notices</b>: ignoring the problem makes errors more likely to reach readers.</span><span class='qd'><b>Tell AI to add more citations next time</b>: more unverified citations increases the chance of fabrication, not less.</span><span class='qd'><b>Remove all citations from every report permanently</b>: stripping citations reduces credibility instead of ensuring they are real.</span>" },
{ id:"D6-036", domain:6, obj:"6.2", diff:"hard", q:"Which principle should guide the design of any AI-assisted workflow that produces public-facing content?", options:["A human verifies and takes responsibility for the final output","AI output is published instantly to be first to market","The workflow hides which parts were AI-generated from the reviewer","No one needs to understand the content as long as it looks polished"], answer:0, explain:"<strong>A human verifies and takes responsibility for the final output</strong> is the guiding principle, ensuring accuracy and accountability before content reaches the public.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI output is published instantly to be first to market</b>: rushing unreviewed output risks publishing errors publicly.</span><span class='qd'><b>The workflow hides which parts were AI-generated from the reviewer</b>: hiding AI portions undermines the reviewer's ability to check them.</span><span class='qd'><b>No one needs to understand the content as long as it looks polished</b>: polish without understanding lets serious errors slip through.</span>" },
{ id:"D6-037", domain:6, obj:"6.2", diff:"medium", q:"A user asks AI to \"role-play as a skeptical customer\" to test a sales pitch. This is an example of using AI for:", options:["Making the final purchase decision","Practice and simulation before a real interaction","Encrypting the sales pitch","Replacing the actual customer permanently"], answer:1, explain:"<strong>Practice and simulation before a real interaction</strong> describes using AI to rehearse, a useful workflow for preparing without real-world consequences.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making the final purchase decision</b>: a simulated customer does not make real purchases.</span><span class='qd'><b>Encrypting the sales pitch</b>: role-play has nothing to do with encryption.</span><span class='qd'><b>Replacing the actual customer permanently</b>: the simulation is for practice, not a substitute for real customers.</span>" },
{ id:"D6-038", domain:6, obj:"6.2", diff:"medium", q:"Which is a good reason to keep the original source alongside an AI-generated summary in a workflow?", options:["So the file takes up more storage space","So the AI can delete the summary later","So no one can ever read the summary","So reviewers can check the summary against the source for accuracy"], answer:3, explain:"<strong>So reviewers can check the summary against the source for accuracy</strong> is the practical reason to retain the source, enabling verification of the condensed version.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>So the file takes up more storage space</b>: increasing storage is not a benefit or a goal.</span><span class='qd'><b>So the AI can delete the summary later</b>: keeping the source is unrelated to deleting outputs.</span><span class='qd'><b>So no one can ever read the summary</b>: retaining the source does not block reading the summary and would defeat its purpose.</span>" },
{ id:"D6-039", domain:6, obj:"6.2", diff:"easy", q:"A user asks AI to brainstorm, then narrows the list, then asks AI to expand the best idea. This shows that AI workflows are often:", options:["Always a single step with no follow-up","Only useful for numbers, never text","Impossible to control by the user","Iterative, cycling between generation and human judgment"], answer:3, explain:"<strong>Iterative, cycling between generation and human judgment</strong> captures how effective AI work often loops between the model producing options and the human deciding direction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always a single step with no follow-up</b>: the described process clearly involves multiple steps.</span><span class='qd'><b>Only useful for numbers, never text</b>: the example is about ideas and text, not numbers.</span><span class='qd'><b>Impossible to control by the user</b>: the user is steering each step, which is the definition of control.</span>" },
{ id:"D6-040", domain:6, obj:"6.2", diff:"medium", q:"A project manager wants a workflow where AI helps write meeting agendas. What makes this workflow trustworthy?", options:["The agenda is sent without anyone reading it","The manager reviews and adjusts each agenda before the meeting","The AI runs the meeting and makes all decisions","The agenda is kept secret from attendees"], answer:1, explain:"<strong>The manager reviews and adjusts each agenda before the meeting</strong> makes the workflow trustworthy by keeping a human accountable for the final agenda.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The agenda is sent without anyone reading it</b>: unreviewed agendas can contain mistakes or omissions.</span><span class='qd'><b>The AI runs the meeting and makes all decisions</b>: decision-making in the meeting belongs to the people, not the tool.</span><span class='qd'><b>The agenda is kept secret from attendees</b>: hiding the agenda undermines the purpose of sharing it.</span>" },
{ id:"D6-041", domain:6, obj:"6.3", diff:"easy", q:"What does \"human-in-the-loop\" mean for an AI system or automation?", options:["The AI operates with no human involvement at all","A human writes all the AI's code by hand","The AI can only run when a human is asleep","A person reviews or approves key AI actions before they take effect"], answer:3, explain:"<strong>A person reviews or approves key AI actions before they take effect</strong> defines human-in-the-loop, which inserts human judgment at important points.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI operates with no human involvement at all</b>: that describes a fully autonomous system, the opposite of human-in-the-loop.</span><span class='qd'><b>A human writes all the AI's code by hand</b>: writing code is unrelated to overseeing the AI's actions at runtime.</span><span class='qd'><b>The AI can only run when a human is asleep</b>: timing of operation has nothing to do with human oversight.</span>" },
{ id:"D6-042", domain:6, obj:"6.3", diff:"easy", q:"Why is human oversight especially important for AI agents that can take actions on their own?", options:["Because agents are always slower than people","Because oversight makes the AI more expensive on purpose","Because unattended actions can cause real harm if the AI makes a mistake","Because agents cannot perform any useful actions"], answer:2, explain:"<strong>Because unattended actions can cause real harm if the AI makes a mistake</strong> is the key reason: agents that act autonomously can produce real consequences, so oversight catches errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because agents are always slower than people</b>: speed is not why oversight matters, and agents are often fast.</span><span class='qd'><b>Because oversight makes the AI more expensive on purpose</b>: the goal of oversight is safety, not cost.</span><span class='qd'><b>Because agents cannot perform any useful actions</b>: agents can be useful; that usefulness is exactly why their actions need checks.</span>" },
{ id:"D6-043", domain:6, obj:"6.3", diff:"easy", q:"An AI agent is set up to draft and send invoices, but it pauses for a manager to approve each one before sending. This approval step is a form of:", options:["Full autonomy","Data encryption","Human-in-the-loop control","Model training"], answer:2, explain:"<strong>Human-in-the-loop control</strong> describes the manager approving each invoice, inserting human judgment before the action completes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full autonomy</b>: pausing for approval is precisely not full autonomy.</span><span class='qd'><b>Data encryption</b>: encryption protects data and is unrelated to approving invoices.</span><span class='qd'><b>Model training</b>: training builds the model and has nothing to do with a runtime approval step.</span>" },
{ id:"D6-044", domain:6, obj:"6.3", diff:"easy", q:"Which situation MOST clearly needs a human approval step before an AI agent acts?", options:["Suggesting a synonym for a word","Sending money or making a purchase","Rewording a sentence for clarity","Counting the words in a paragraph"], answer:1, explain:"<strong>Sending money or making a purchase</strong> is high-impact and hard to reverse, so it clearly warrants human approval before the agent proceeds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Suggesting a synonym for a word</b>: a synonym suggestion is trivial and low-risk.</span><span class='qd'><b>Rewording a sentence for clarity</b>: rewording text carries little consequence and is easy to review after the fact.</span><span class='qd'><b>Counting the words in a paragraph</b>: counting words has no meaningful risk.</span>" },
{ id:"D6-045", domain:6, obj:"6.3", diff:"easy", q:"What is a \"kill switch\" or stop control in the context of AI automation?", options:["A feature that makes the AI run forever","A tool that hides the AI's mistakes","A way for a human to halt the AI's actions quickly if something goes wrong","A method for training the model faster"], answer:2, explain:"<strong>A way for a human to halt the AI's actions quickly if something goes wrong</strong> defines a stop control, a basic safety mechanism for keeping humans in charge.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A feature that makes the AI run forever</b>: a stop control does the opposite by allowing a halt.</span><span class='qd'><b>A tool that hides the AI's mistakes</b>: a kill switch stops actions; it does not conceal errors.</span><span class='qd'><b>A method for training the model faster</b>: training speed is unrelated to an emergency stop.</span>" },
{ id:"D6-046", domain:6, obj:"6.3", diff:"medium", q:"An AI agent has permission to delete files automatically to \"clean up\" storage. What oversight measure is MOST important?", options:["Give the agent even more permissions","Require confirmation or a recoverable trash before permanent deletion","Turn off all logging of its actions","Let it run only on weekends"], answer:1, explain:"<strong>Require confirmation or a recoverable trash before permanent deletion</strong> protects against irreversible mistakes by adding a human check or a safety net.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give the agent even more permissions</b>: broader permissions increase risk rather than adding oversight.</span><span class='qd'><b>Turn off all logging of its actions</b>: disabling logs removes the ability to review what happened.</span><span class='qd'><b>Let it run only on weekends</b>: scheduling does not address the danger of permanent deletion.</span>" },
{ id:"D6-047", domain:6, obj:"6.3", diff:"medium", q:"Why should AI agents that take actions keep an audit log?", options:["So the agent can hide its behavior from managers","Because logs make the AI more creative","So humans can review what the agent did and why, and investigate problems","Because logs replace the need for any oversight"], answer:2, explain:"<strong>So humans can review what the agent did and why, and investigate problems</strong> is the purpose of an audit log: it provides accountability and a trail for troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>So the agent can hide its behavior from managers</b>: logs reveal behavior; they do not hide it.</span><span class='qd'><b>Because logs make the AI more creative</b>: logging records actions and has no effect on creativity.</span><span class='qd'><b>Because logs replace the need for any oversight</b>: logs support oversight but do not eliminate the need for it.</span>" },
{ id:"D6-048", domain:6, obj:"6.3", diff:"medium", q:"An AI assistant is empowered to reply to customer emails automatically. What is a sensible boundary to set?", options:["Escalate sensitive or complex issues to a human instead of answering alone","Let it promise refunds of any size on its own","Have it answer legal questions definitively without review","Allow it to close accounts without confirmation"], answer:0, explain:"<strong>Escalate sensitive or complex issues to a human instead of answering alone</strong> sets an appropriate limit, letting the AI handle routine cases while humans manage higher-risk ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let it promise refunds of any size on its own</b>: unlimited refund authority is a financial risk that needs human control.</span><span class='qd'><b>Have it answer legal questions definitively without review</b>: definitive legal answers carry liability and need human oversight.</span><span class='qd'><b>Allow it to close accounts without confirmation</b>: closing accounts is consequential and should require confirmation.</span>" },
{ id:"D6-049", domain:6, obj:"6.3", diff:"medium", q:"Which practice BEST limits the damage an AI agent can do if it malfunctions?", options:["Give it administrator access to everything for convenience","Remove all monitoring so it runs freely","Grant it only the minimum permissions needed for its task","Let it act without any spending or action limits"], answer:2, explain:"<strong>Grant it only the minimum permissions needed for its task</strong> follows least privilege, so a malfunction cannot reach systems the agent never needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give it administrator access to everything for convenience</b>: broad access maximizes potential damage from a malfunction.</span><span class='qd'><b>Remove all monitoring so it runs freely</b>: removing monitoring means problems go unnoticed.</span><span class='qd'><b>Let it act without any spending or action limits</b>: no limits allows unbounded harm if it misbehaves.</span>" },
{ id:"D6-050", domain:6, obj:"6.3", diff:"medium", q:"An AI scheduling agent starts double-booking meetings. What is the FIRST oversight-minded response?", options:["Let it keep running and hope it self-corrects","Delete all the affected calendars","Give the agent access to more calendars","Pause the agent and review its recent actions before letting it continue"], answer:3, explain:"<strong>Pause the agent and review its recent actions before letting it continue</strong> is the responsible first step, stopping the harm and investigating the cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let it keep running and hope it self-corrects</b>: allowing it to continue risks more double-bookings.</span><span class='qd'><b>Delete all the affected calendars</b>: deleting calendars is destructive and does not fix the agent.</span><span class='qd'><b>Give the agent access to more calendars</b>: expanding its reach while it is misbehaving increases the problem.</span>" },
{ id:"D6-051", domain:6, obj:"6.3", diff:"medium", q:"Which statement about human oversight of AI automation is MOST accurate?", options:["Every AI action needs identical, maximum oversight regardless of risk","Oversight is only needed for free tools","Oversight should scale with the risk and impact of the AI's actions","Oversight can be skipped if the AI seems confident"], answer:2, explain:"<strong>Oversight should scale with the risk and impact of the AI's actions</strong> reflects a proportionate approach: high-stakes actions get more scrutiny than trivial ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Every AI action needs identical, maximum oversight regardless of risk</b>: applying maximum oversight everywhere is impractical and ignores risk differences.</span><span class='qd'><b>Oversight is only needed for free tools</b>: the need for oversight depends on impact, not price.</span><span class='qd'><b>Oversight can be skipped if the AI seems confident</b>: confident-sounding AI can still be wrong, so confidence is no substitute for review.</span>" },
{ id:"D6-052", domain:6, obj:"6.3", diff:"medium", q:"A company lets an AI agent post to its official social media account. What oversight setup is MOST prudent?", options:["Let the agent post anything instantly to stay active","Give the agent the login and stop monitoring it","Require a human to approve each post before it goes live","Allow it to delete the company's past posts freely"], answer:2, explain:"<strong>Require a human to approve each post before it goes live</strong> protects the brand by ensuring a person checks public messages before they are published.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let the agent post anything instantly to stay active</b>: instant unreviewed posting risks embarrassing or harmful messages.</span><span class='qd'><b>Give the agent the login and stop monitoring it</b>: unmonitored access to an official account is a serious risk.</span><span class='qd'><b>Allow it to delete the company's past posts freely</b>: unrestricted deletion could destroy valuable records.</span>" },
{ id:"D6-053", domain:6, obj:"6.3", diff:"hard", q:"An organization deploys an AI agent to process refunds. Leadership wants efficiency but also safety. Which design BEST balances both?", options:["Auto-approve every refund of any amount to be fast","Send all refunds to a human, defeating the automation's purpose","Let the agent auto-approve small routine refunds and route larger ones to a human","Let the agent set its own refund limits without oversight"], answer:2, explain:"<strong>Let the agent auto-approve small routine refunds and route larger ones to a human</strong> is a tiered design that automates low-risk cases while keeping humans on high-impact ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Auto-approve every refund of any amount to be fast</b>: unlimited auto-approval removes control over large payouts.</span><span class='qd'><b>Send all refunds to a human, defeating the automation's purpose</b>: routing everything to humans gives up the efficiency benefit entirely.</span><span class='qd'><b>Let the agent set its own refund limits without oversight</b>: allowing the agent to set its own limits removes meaningful human control.</span>" },
{ id:"D6-054", domain:6, obj:"6.3", diff:"hard", q:"An AI agent chains multiple tools together (search, then email, then payment). Where is human review MOST critical?", options:["Before the irreversible or high-impact step, such as sending payment","Only during the initial search step","At no step, since the chain is automated","Only after all steps have already completed"], answer:0, explain:"<strong>Before the irreversible or high-impact step, such as sending payment</strong> is where a check matters most, because that action is costly and hard to undo.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only during the initial search step</b>: searching is low-risk; the payment step is the dangerous one.</span><span class='qd'><b>At no step, since the chain is automated</b>: automation does not remove the need to guard the high-impact step.</span><span class='qd'><b>Only after all steps have already completed</b>: reviewing after payment is too late to prevent a bad transaction.</span>" },
{ id:"D6-055", domain:6, obj:"6.3", diff:"hard", q:"A team wants an AI agent to act more independently over time. What is the safest way to increase its autonomy?", options:["Gradually expand its authority as it proves reliable, keeping logs and limits","Grant full autonomy immediately to save time","Remove logging once it seems to work","Let it expand its own permissions whenever it wants"], answer:0, explain:"<strong>Gradually expand its authority as it proves reliable, keeping logs and limits</strong> is the cautious path: earn trust incrementally while retaining oversight mechanisms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grant full autonomy immediately to save time</b>: jumping to full autonomy skips the evidence that it is safe.</span><span class='qd'><b>Remove logging once it seems to work</b>: removing logs eliminates the ability to catch later failures.</span><span class='qd'><b>Let it expand its own permissions whenever it wants</b>: self-expanding permissions defeat the point of human control.</span>" },
{ id:"D6-056", domain:6, obj:"6.3", diff:"hard", q:"Which failure mode does human-in-the-loop oversight MOST directly protect against?", options:["The AI confidently taking a wrong action that a human could have caught","The AI running out of electricity","The AI using too little memory","The AI producing output too quickly to read"], answer:0, explain:"<strong>The AI confidently taking a wrong action that a human could have caught</strong> is exactly what oversight guards against, since a reviewer can stop a plausible-looking mistake.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI running out of electricity</b>: power supply is an infrastructure issue, not something human review addresses.</span><span class='qd'><b>The AI using too little memory</b>: memory usage is a technical resource matter unrelated to oversight.</span><span class='qd'><b>The AI producing output too quickly to read</b>: output speed is not the harm oversight is designed to prevent.</span>" },
{ id:"D6-057", domain:6, obj:"6.3", diff:"medium", q:"An AI agent is allowed to book travel automatically. Which safeguard reduces risk the MOST?", options:["Let it book any flight at any price","Hide the bookings from the traveler","Give it access to the company bank account directly","Set spending caps and require approval above a threshold"], answer:3, explain:"<strong>Set spending caps and require approval above a threshold</strong> limits financial exposure while still letting the agent handle routine bookings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let it book any flight at any price</b>: unlimited spending is a clear financial risk.</span><span class='qd'><b>Hide the bookings from the traveler</b>: concealing bookings prevents the traveler from catching mistakes.</span><span class='qd'><b>Give it access to the company bank account directly</b>: direct bank access dramatically increases potential harm.</span>" },
{ id:"D6-058", domain:6, obj:"6.3", diff:"medium", q:"What is the main risk of \"automation complacency\" when overseeing AI?", options:["Humans check the AI too carefully and slow down","The AI refuses to accept human corrections","The AI becomes unable to produce output","Humans rubber-stamp AI output without truly checking it"], answer:3, explain:"<strong>Humans rubber-stamp AI output without truly checking it</strong> describes automation complacency, where over-trust erodes the value of the human review step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Humans check the AI too carefully and slow down</b>: excessive care is the opposite of complacency.</span><span class='qd'><b>The AI refuses to accept human corrections</b>: complacency is about human behavior, not the AI rejecting input.</span><span class='qd'><b>The AI becomes unable to produce output</b>: an inability to produce output is unrelated to over-trust.</span>" },
{ id:"D6-059", domain:6, obj:"6.3", diff:"easy", q:"For an AI agent that can take real actions, which combination provides good oversight?", options:["Clear limits, logging, and a way to stop or approve actions","No limits and no logging","A single unmonitored login shared by everyone","Permission to do anything with no records"], answer:0, explain:"<strong>Clear limits, logging, and a way to stop or approve actions</strong> together form a solid oversight foundation for an action-taking agent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No limits and no logging</b>: removing limits and logs leaves no control or visibility.</span><span class='qd'><b>A single unmonitored login shared by everyone</b>: a shared, unmonitored login destroys accountability.</span><span class='qd'><b>Permission to do anything with no records</b>: unlimited permission without records is the opposite of oversight.</span>" },
{ id:"D6-060", domain:6, obj:"6.3", diff:"medium", q:"A new AI feature can auto-approve expense reports. Before enabling full automation, what is the WISEST first step?", options:["Enable full automation on day one across the company","Disable the ability to ever review its decisions","Let it approve executives' expenses only, with no checks","Run it in a review mode where a human confirms decisions for a while"], answer:3, explain:"<strong>Run it in a review mode where a human confirms decisions for a while</strong> lets the team build confidence and catch errors before removing the human check.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable full automation on day one across the company</b>: immediate full automation skips the trust-building phase.</span><span class='qd'><b>Disable the ability to ever review its decisions</b>: removing review capability eliminates oversight entirely.</span><span class='qd'><b>Let it approve executives' expenses only, with no checks</b>: unchecked approval of any expenses, especially high-value ones, is risky.</span>" },
{ id:"D6-061", domain:6, obj:"6.4", diff:"easy", q:"When is disclosing that you used AI MOST clearly appropriate?", options:["Only when the AI makes a mistake","Never, because AI use is always secret","When submitting AI-assisted work where the reader expects to know how it was produced","Only if a law forces you to at gunpoint"], answer:2, explain:"<strong>When submitting AI-assisted work where the reader expects to know how it was produced</strong> is a clear case for disclosure, honoring the audience's reasonable expectations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only when the AI makes a mistake</b>: disclosure is about transparency, not limited to error situations.</span><span class='qd'><b>Never, because AI use is always secret</b>: treating AI use as always secret undermines honesty and trust.</span><span class='qd'><b>Only if a law forces you to at gunpoint</b>: ethical disclosure often applies even without a legal mandate.</span>" },
{ id:"D6-062", domain:6, obj:"6.4", diff:"easy", q:"A student uses AI to help write an essay for a class that requires original student work. What should the student do?", options:["Follow the instructor's or institution's policy on AI use and disclose as required","Hide the AI use because grades matter more than honesty","Assume AI is always banned and never ask","Claim a friend wrote it instead"], answer:0, explain:"<strong>Follow the instructor's or institution's policy on AI use and disclose as required</strong> is the responsible course, respecting academic rules and transparency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hide the AI use because grades matter more than honesty</b>: hiding use to protect a grade is dishonest.</span><span class='qd'><b>Assume AI is always banned and never ask</b>: assuming without checking can be wrong; asking clarifies the policy.</span><span class='qd'><b>Claim a friend wrote it instead</b>: lying about authorship is dishonest and worse than the original issue.</span>" },
{ id:"D6-063", domain:6, obj:"6.4", diff:"easy", q:"What is an \"AI-use statement\"?", options:["A legal contract signed with the AI vendor","A password that unlocks the AI tool","A guarantee that the AI made no mistakes","A brief note describing how and where AI was used in producing the work"], answer:3, explain:"<strong>A brief note describing how and where AI was used in producing the work</strong> defines an AI-use statement, which promotes transparency about the tool's role.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A legal contract signed with the AI vendor</b>: an AI-use statement is a disclosure to readers, not a vendor contract.</span><span class='qd'><b>A password that unlocks the AI tool</b>: it has nothing to do with access credentials.</span><span class='qd'><b>A guarantee that the AI made no mistakes</b>: a use statement discloses involvement; it makes no accuracy guarantee.</span>" },
{ id:"D6-064", domain:6, obj:"6.4", diff:"easy", q:"Which is a good reason to disclose AI assistance in a published article?", options:["It guarantees the article will go viral","It transfers all responsibility to the AI","It hides the author's identity","It maintains honesty and lets readers weigh the content appropriately"], answer:3, explain:"<strong>It maintains honesty and lets readers weigh the content appropriately</strong> is a sound reason: transparency helps readers judge the work fairly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the article will go viral</b>: disclosure has no effect on virality.</span><span class='qd'><b>It transfers all responsibility to the AI</b>: the human author remains responsible regardless of disclosure.</span><span class='qd'><b>It hides the author's identity</b>: disclosure reveals how work was made; it does not conceal the author.</span>" },
{ id:"D6-065", domain:6, obj:"6.4", diff:"easy", q:"A colleague asks if they must disclose using spell-check-like AI grammar fixes in an internal email. What is the MOST reasonable stance?", options:["You must always attach a legal notice to every email","You must never use grammar tools","You must delete the email if AI touched it","Minor tooling like grammar help usually needs no formal disclosure, but follow your organization's norms"], answer:3, explain:"<strong>Minor tooling like grammar help usually needs no formal disclosure, but follow your organization's norms</strong> reflects proportionate judgment: trivial assistance rarely requires disclosure, though policies vary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>You must always attach a legal notice to every email</b>: legal notices on every email are excessive for minor grammar help.</span><span class='qd'><b>You must never use grammar tools</b>: banning grammar tools is unnecessary and unrealistic.</span><span class='qd'><b>You must delete the email if AI touched it</b>: deleting the email is an overreaction to minor assistance.</span>" },
{ id:"D6-066", domain:6, obj:"6.4", diff:"medium", q:"A freelancer delivers a logo \"designed by hand\" but actually generated it with AI. Why is this problematic?", options:["AI logos are always illegal","Clients never care how work is made","Hand-drawn logos are the only valid ones","It misrepresents how the work was made, which is dishonest to the client"], answer:3, explain:"<strong>It misrepresents how the work was made, which is dishonest to the client</strong> identifies the core issue: the false claim about the process breaks trust.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI logos are always illegal</b>: using AI for a logo is not inherently illegal; the problem is the lie.</span><span class='qd'><b>Clients never care how work is made</b>: many clients do care, and the claim was specifically made to them.</span><span class='qd'><b>Hand-drawn logos are the only valid ones</b>: AI-made logos can be valid; misrepresentation is what is wrong.</span>" },
{ id:"D6-067", domain:6, obj:"6.4", diff:"medium", q:"An organization publishes a report that AI helped draft. Which AI-use statement is BEST?", options:["\"No humans were involved in this report.\"","\"AI tools assisted in drafting; all content was reviewed and verified by our team.\"","\"This report is guaranteed error-free by AI.\"","\"AI wrote this, so we are not responsible for it.\""], answer:1, explain:"<strong>\"AI tools assisted in drafting; all content was reviewed and verified by our team.\"</strong> is honest, clear, and preserves human accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"No humans were involved in this report.\"</b>: this is likely false and abandons accountability.</span><span class='qd'><b>\"This report is guaranteed error-free by AI.\"</b>: no AI can guarantee error-free content.</span><span class='qd'><b>\"AI wrote this, so we are not responsible for it.\"</b>: disclaiming responsibility is not acceptable; the organization owns its output.</span>" },
{ id:"D6-068", domain:6, obj:"6.4", diff:"medium", q:"When deciding whether to disclose AI use, which factor matters MOST?", options:["Whether the audience or context reasonably expects transparency about how work was made","The brand of AI tool you used","How fast the AI responded","How many prompts you typed"], answer:0, explain:"<strong>Whether the audience or context reasonably expects transparency about how work was made</strong> is the central factor, guiding disclosure toward what stakeholders reasonably need to know.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The brand of AI tool you used</b>: the specific tool brand rarely affects the disclosure decision.</span><span class='qd'><b>How fast the AI responded</b>: response speed is irrelevant to transparency.</span><span class='qd'><b>How many prompts you typed</b>: the number of prompts does not determine whether disclosure is appropriate.</span>" },
{ id:"D6-069", domain:6, obj:"6.4", diff:"medium", q:"A journalist uses AI to summarize documents but presents the summary as their own careful reading. What is the ethical issue?", options:["There is no issue; summaries never matter","Misleading readers about the process and possibly missing AI errors","AI summaries are always perfect, so disclosure is pointless","Journalists are never allowed to read documents"], answer:1, explain:"<strong>Misleading readers about the process and possibly missing AI errors</strong> captures the problem: misrepresenting the method and skipping verification can spread mistakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>There is no issue; summaries never matter</b>: summaries can shape reporting, so accuracy and honesty matter.</span><span class='qd'><b>AI summaries are always perfect, so disclosure is pointless</b>: AI summaries can be wrong, which is why care and honesty are needed.</span><span class='qd'><b>Journalists are never allowed to read documents</b>: reading documents is normal journalism and not the issue.</span>" },
{ id:"D6-070", domain:6, obj:"6.4", diff:"medium", q:"A company's policy says AI-generated customer-facing content must be labeled. An employee posts an AI-written blog without a label. This is BEST described as:", options:["A policy violation that undermines transparency","A creative choice with no downside","Required by law everywhere","A way to improve accuracy"], answer:0, explain:"<strong>A policy violation that undermines transparency</strong> correctly frames the omission, since the company required labeling and it was skipped.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A creative choice with no downside</b>: ignoring policy has downsides including lost trust and discipline.</span><span class='qd'><b>Required by law everywhere</b>: this is a company policy matter, not a universal legal requirement.</span><span class='qd'><b>A way to improve accuracy</b>: skipping a label does nothing to improve accuracy.</span>" },
{ id:"D6-071", domain:6, obj:"6.4", diff:"medium", q:"Which disclosure approach BEST balances transparency and practicality for routine AI-assisted work?", options:["Disclose nothing ever to keep things simple","Disclose AI use proportionate to the stakes and audience expectations","Attach a ten-page AI affidavit to every task","Only disclose after being caught"], answer:1, explain:"<strong>Disclose AI use proportionate to the stakes and audience expectations</strong> is balanced: significant or expectation-sensitive work gets disclosed clearly while trivial help does not demand heavy process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disclose nothing ever to keep things simple</b>: never disclosing sacrifices honesty for convenience.</span><span class='qd'><b>Attach a ten-page AI affidavit to every task</b>: excessive documentation is impractical for routine work.</span><span class='qd'><b>Only disclose after being caught</b>: disclosing only when caught is reactive and dishonest.</span>" },
{ id:"D6-072", domain:6, obj:"6.4", diff:"hard", q:"A researcher submits a paper to a journal that requires authors to declare AI assistance. They used AI to draft sections but omitted the declaration. What is the BEST characterization?", options:["An acceptable shortcut since AI is common","Only a problem if the AI text was wrong","A breach of the journal's transparency requirements and research integrity norms","Irrelevant because AI cannot be an author"], answer:2, explain:"<strong>A breach of the journal's transparency requirements and research integrity norms</strong> is accurate: the venue mandated disclosure, and omitting it violates its rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An acceptable shortcut since AI is common</b>: prevalence does not excuse ignoring a stated requirement.</span><span class='qd'><b>Only a problem if the AI text was wrong</b>: the violation is the missing declaration, regardless of accuracy.</span><span class='qd'><b>Irrelevant because AI cannot be an author</b>: whether AI can be an author is separate from the required disclosure of its use.</span>" },
{ id:"D6-073", domain:6, obj:"6.4", diff:"hard", q:"A marketing team debates whether to disclose that testimonials were written with AI help based on real customer interviews. Which stance is MOST defensible?", options:["Present them as fully customer-written to seem authentic","Delete the interviews to avoid the question","Disclose the AI assistance so readers are not misled about authorship","Claim a famous copywriter wrote them"], answer:2, explain:"<strong>Disclose the AI assistance so readers are not misled about authorship</strong> is the honest and defensible path, avoiding deception about who wrote the testimonials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Present them as fully customer-written to seem authentic</b>: this misrepresents authorship and deceives readers.</span><span class='qd'><b>Delete the interviews to avoid the question</b>: destroying source material to dodge disclosure is evasive and wasteful.</span><span class='qd'><b>Claim a famous copywriter wrote them</b>: a false authorship claim is outright dishonest.</span>" },
{ id:"D6-074", domain:6, obj:"6.4", diff:"hard", q:"Why can excessive or vague AI disclaimers sometimes be as unhelpful as no disclosure?", options:["They make the AI legally liable for everything","They can obscure who is actually accountable and what was verified","They guarantee the content is false","They always violate the law"], answer:1, explain:"<strong>They can obscure who is actually accountable and what was verified</strong> is the concern: a blanket, vague disclaimer can hide responsibility instead of clarifying it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They make the AI legally liable for everything</b>: disclaimers do not shift legal liability onto the AI.</span><span class='qd'><b>They guarantee the content is false</b>: a disclaimer does not make content false.</span><span class='qd'><b>They always violate the law</b>: disclaimers are not inherently illegal.</span>" },
{ id:"D6-075", domain:6, obj:"6.4", diff:"medium", q:"An employee is unsure whether their workplace allows AI for client deliverables. What is the BEST first action?", options:["Check the organization's AI-use policy or ask a manager before proceeding","Assume it is allowed and use AI without asking","Assume it is banned and refuse all AI forever","Use AI secretly and never mention it"], answer:0, explain:"<strong>Check the organization's AI-use policy or ask a manager before proceeding</strong> is the responsible step, resolving uncertainty through the proper channel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is allowed and use AI without asking</b>: assuming permission can violate policy.</span><span class='qd'><b>Assume it is banned and refuse all AI forever</b>: assuming a ban without checking may forgo legitimate, approved use.</span><span class='qd'><b>Use AI secretly and never mention it</b>: secret use undermines transparency and may breach policy.</span>" },
{ id:"D6-076", domain:6, obj:"6.4", diff:"medium", q:"Which is the MOST honest way to credit AI in a slide deck you created with AI help?", options:["Sign it as entirely your own unaided work","Credit a coworker who did not help","Leave a note saying the AI is fully responsible","Add a short note that AI assisted and you reviewed the content"], answer:3, explain:"<strong>Add a short note that AI assisted and you reviewed the content</strong> is honest and keeps your accountability intact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sign it as entirely your own unaided work</b>: claiming unaided work when AI helped is misleading.</span><span class='qd'><b>Credit a coworker who did not help</b>: false credit misrepresents who did the work.</span><span class='qd'><b>Leave a note saying the AI is fully responsible</b>: you remain responsible for content you present.</span>" },
{ id:"D6-077", domain:6, obj:"6.4", diff:"easy", q:"A contest requires entries to be entirely human-made. Submitting AI-generated art without disclosure would be:", options:["Perfectly fine since AI art looks good","A violation of the contest rules and dishonest","Encouraged by all contests","Only wrong if the art is ugly"], answer:1, explain:"<strong>A violation of the contest rules and dishonest</strong> is correct because the rules require human-made work and disclosure would be expected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perfectly fine since AI art looks good</b>: quality does not excuse breaking the rules.</span><span class='qd'><b>Encouraged by all contests</b>: this contest specifically forbids it.</span><span class='qd'><b>Only wrong if the art is ugly</b>: the violation exists regardless of how the art looks.</span>" },
{ id:"D6-078", domain:6, obj:"6.4", diff:"medium", q:"A company adds \"parts of this response were generated with AI and reviewed by staff\" to chatbot replies. This practice MOST supports which value?", options:["Faster server performance","Transparency with users","Lower electricity costs","Stronger password security"], answer:1, explain:"<strong>Transparency with users</strong> is the value served, letting users know AI was involved while a human reviewed the output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster server performance</b>: a disclosure note does not affect server speed.</span><span class='qd'><b>Lower electricity costs</b>: the note has no bearing on energy use.</span><span class='qd'><b>Stronger password security</b>: transparency about AI is unrelated to password security.</span>" },
{ id:"D6-079", domain:6, obj:"6.4", diff:"easy", q:"Which statement about disclosing AI use is MOST accurate?", options:["AI use must be hidden in all professional settings","AI use never needs to be considered","Disclosure norms depend on context, audience, and any applicable policies","Only celebrities must disclose AI use"], answer:2, explain:"<strong>Disclosure norms depend on context, audience, and any applicable policies</strong> reflects reality: expectations vary by situation rather than following a single fixed rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI use must be hidden in all professional settings</b>: hiding use everywhere conflicts with honesty and many policies.</span><span class='qd'><b>AI use never needs to be considered</b>: disclosure often does need consideration.</span><span class='qd'><b>Only celebrities must disclose AI use</b>: disclosure norms apply broadly, not just to celebrities.</span>" },
{ id:"D6-080", domain:6, obj:"6.4", diff:"medium", q:"A teacher permits AI brainstorming but requires students to note where AI helped. A student who followed this and added a brief AI-use note has:", options:["Cheated despite the permission","Acted transparently and within the stated rules","Broken the law","Guaranteed a perfect grade"], answer:1, explain:"<strong>Acted transparently and within the stated rules</strong> is correct, since the student both used allowed assistance and disclosed it as required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cheated despite the permission</b>: following permitted rules is not cheating.</span><span class='qd'><b>Broken the law</b>: disclosing permitted AI help breaks no law.</span><span class='qd'><b>Guaranteed a perfect grade</b>: disclosure does not guarantee any particular grade.</span>" },
{ id:"D6-081", domain:6, obj:"6.5", diff:"easy", q:"In an AI-aware team, what does the \"prompter\" role primarily do?", options:["Signs off on legal contracts","Crafts clear instructions to get useful output from the AI","Repairs the office network","Approves the company budget"], answer:1, explain:"<strong>Crafts clear instructions to get useful output from the AI</strong> defines the prompter, who focuses on framing effective requests.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signs off on legal contracts</b>: legal sign-off is a separate responsibility, not the prompter's job.</span><span class='qd'><b>Repairs the office network</b>: network repair is an IT task unrelated to prompting.</span><span class='qd'><b>Approves the company budget</b>: budget approval is a management function, not prompting.</span>" },
{ id:"D6-082", domain:6, obj:"6.5", diff:"easy", q:"What does the \"verifier\" role focus on in an AI-supported workflow?", options:["Writing the very first prompt","Checking the AI's output for accuracy and problems","Buying the AI subscription","Designing the office layout"], answer:1, explain:"<strong>Checking the AI's output for accuracy and problems</strong> is the verifier's core job, ensuring the result can be trusted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Writing the very first prompt</b>: writing prompts is the prompter's role, not the verifier's.</span><span class='qd'><b>Buying the AI subscription</b>: purchasing tools is a procurement task, not verification.</span><span class='qd'><b>Designing the office layout</b>: office design is unrelated to checking AI output.</span>" },
{ id:"D6-083", domain:6, obj:"6.5", diff:"easy", q:"What is the main responsibility of the \"editor\" role when working with AI output?", options:["Turning the computer on each morning","Setting the AI's electricity bill","Deciding company-wide salaries","Refining the AI's draft for tone, clarity, and correctness"], answer:3, explain:"<strong>Refining the AI's draft for tone, clarity, and correctness</strong> describes the editor, who polishes raw AI output into finished work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Turning the computer on each morning</b>: powering on a device is not an editing responsibility.</span><span class='qd'><b>Setting the AI's electricity bill</b>: utility costs are unrelated to editing.</span><span class='qd'><b>Deciding company-wide salaries</b>: salary decisions are a management matter, not editing.</span>" },
{ id:"D6-084", domain:6, obj:"6.5", diff:"easy", q:"When explaining AI to a nonexpert colleague, which approach is BEST?", options:["Recite technical model architecture details","Use plain language and relatable examples, avoiding heavy jargon","Refuse to explain because it is too complex","Tell them AI is magic and cannot be understood"], answer:1, explain:"<strong>Use plain language and relatable examples, avoiding heavy jargon</strong> is the most effective way to help a nonexpert understand AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recite technical model architecture details</b>: heavy technical detail overwhelms a nonexpert.</span><span class='qd'><b>Refuse to explain because it is too complex</b>: refusing to explain is unhelpful and dismissive.</span><span class='qd'><b>Tell them AI is magic and cannot be understood</b>: calling it magic is misleading and discourages learning.</span>" },
{ id:"D6-085", domain:6, obj:"6.5", diff:"medium", q:"A team assigns one person to write prompts, another to fact-check outputs, and another to polish the text. Why is dividing these roles useful?", options:["It makes the process slower for no reason","It removes the need for any human to think","It brings focused attention and accountability to each stage of the work","It guarantees the AI never makes mistakes"], answer:2, explain:"<strong>It brings focused attention and accountability to each stage of the work</strong> explains the benefit: clear roles improve quality and make responsibility explicit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the process slower for no reason</b>: the division adds value, not pointless delay.</span><span class='qd'><b>It removes the need for any human to think</b>: each role requires human thought, not less of it.</span><span class='qd'><b>It guarantees the AI never makes mistakes</b>: role division helps catch mistakes but cannot guarantee none occur.</span>" },
{ id:"D6-086", domain:6, obj:"6.5", diff:"medium", q:"A nonexpert asks, \"Does the chatbot actually know things?\" Which explanation is MOST accurate and clear?", options:["It has a human brain and true understanding","It looks up every answer in a verified encyclopedia","It is always correct because it is a computer","It predicts likely text based on patterns, so it can sound right but be wrong"], answer:3, explain:"<strong>It predicts likely text based on patterns, so it can sound right but be wrong</strong> is an accurate, accessible explanation of how a language model behaves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It has a human brain and true understanding</b>: a chatbot does not have a brain or genuine understanding.</span><span class='qd'><b>It looks up every answer in a verified encyclopedia</b>: it generates text rather than consulting a guaranteed reference for each answer.</span><span class='qd'><b>It is always correct because it is a computer</b>: being a computer does not make its outputs always correct.</span>" },
{ id:"D6-087", domain:6, obj:"6.5", diff:"medium", q:"Which skill is becoming MORE valuable as AI tools spread in the workplace?", options:["The ability to accept any AI answer without question","The ability to avoid learning new tools","The ability to critically evaluate and verify AI output","The ability to type faster than everyone"], answer:2, explain:"<strong>The ability to critically evaluate and verify AI output</strong> grows in value because trustworthy use depends on judging AI results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The ability to accept any AI answer without question</b>: uncritical acceptance is a liability, not a valuable skill.</span><span class='qd'><b>The ability to avoid learning new tools</b>: avoiding learning makes someone less adaptable.</span><span class='qd'><b>The ability to type faster than everyone</b>: typing speed is minor compared with judgment about AI output.</span>" },
{ id:"D6-088", domain:6, obj:"6.5", diff:"medium", q:"A manager wants to explain to leadership why the team still needs human reviewers even with AI. What is the STRONGEST point?", options:["AI can produce confident errors, so human review protects quality and accountability","AI is too slow, so humans must do everything","Human reviewers make the AI run faster","AI cannot produce any output without reviewers"], answer:0, explain:"<strong>AI can produce confident errors, so human review protects quality and accountability</strong> is the strongest argument for retaining human reviewers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI is too slow, so humans must do everything</b>: AI is often fast; speed is not the reason for review.</span><span class='qd'><b>Human reviewers make the AI run faster</b>: reviewers check output; they do not accelerate the model.</span><span class='qd'><b>AI cannot produce any output without reviewers</b>: AI can produce output on its own; reviewers ensure it is trustworthy.</span>" },
{ id:"D6-089", domain:6, obj:"6.5", diff:"medium", q:"When explaining an AI feature to nonexpert users, which practice builds appropriate trust?", options:["Be honest about what it can and cannot do, including its limits","Claim it is flawless to encourage adoption","Hide that AI is involved at all","Use only complex jargon to sound impressive"], answer:0, explain:"<strong>Be honest about what it can and cannot do, including its limits</strong> builds calibrated trust so users rely on the tool appropriately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Claim it is flawless to encourage adoption</b>: overstating capability leads to misplaced trust and later disappointment.</span><span class='qd'><b>Hide that AI is involved at all</b>: concealing AI involvement undermines transparency.</span><span class='qd'><b>Use only complex jargon to sound impressive</b>: jargon confuses nonexperts rather than informing them.</span>" },
{ id:"D6-090", domain:6, obj:"6.5", diff:"medium", q:"A new hire is unsure how to write effective prompts. Which is the BEST advice for the prompter role?", options:["Keep prompts as vague as possible","Never give the AI any context","Be specific about the goal, audience, and format you want","Ask for everything in one enormous sentence with no structure"], answer:2, explain:"<strong>Be specific about the goal, audience, and format you want</strong> is proven guidance that helps the AI produce more useful results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep prompts as vague as possible</b>: vagueness produces unfocused output.</span><span class='qd'><b>Never give the AI any context</b>: withholding context makes results less relevant.</span><span class='qd'><b>Ask for everything in one enormous sentence with no structure</b>: an unstructured mega-sentence is hard for the AI to follow.</span>" },
{ id:"D6-091", domain:6, obj:"6.5", diff:"hard", q:"A cross-functional team is formalizing AI roles. Which combination BEST ensures quality output?", options:["A prompter to frame requests, a verifier to check facts, and an editor to refine, all with human accountability","A single prompter who publishes output unchecked","A verifier who only reads the prompt, not the output","An editor who rewrites content without knowing the goal"], answer:0, explain:"<strong>A prompter to frame requests, a verifier to check facts, and an editor to refine, all with human accountability</strong> covers input, checking, and polishing while keeping people responsible.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single prompter who publishes output unchecked</b>: skipping verification and editing risks errors reaching the audience.</span><span class='qd'><b>A verifier who only reads the prompt, not the output</b>: checking the prompt instead of the output misses actual mistakes.</span><span class='qd'><b>An editor who rewrites content without knowing the goal</b>: editing blind to the goal can distort the intended message.</span>" },
{ id:"D6-092", domain:6, obj:"6.5", diff:"hard", q:"An executive says, \"With AI, we can eliminate the verifier role to save money.\" What is the BEST counterpoint?", options:["Verifiers are the only people who understand AI","AI cannot function without a verifier present","Removing verification raises the risk of shipping confident but wrong AI output","Verification is a legal requirement in every country"], answer:2, explain:"<strong>Removing verification raises the risk of shipping confident but wrong AI output</strong> is the strongest, most accurate counterpoint about why checking matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verifiers are the only people who understand AI</b>: many roles can understand AI; this overstates the claim.</span><span class='qd'><b>AI cannot function without a verifier present</b>: AI can run without a verifier; the point is that output would be riskier.</span><span class='qd'><b>Verification is a legal requirement in every country</b>: verification is good practice but not a universal legal mandate.</span>" },
{ id:"D6-093", domain:6, obj:"6.5", diff:"hard", q:"You must explain to a skeptical board why AI \"hallucinations\" happen, in nonexpert terms. Which explanation is BEST?", options:["The tool intentionally lies to deceive the board","The tool has emotions that cause it to err","The tool is broken and should never be used","The tool generates plausible-sounding text from patterns and can fill gaps with made-up details"], answer:3, explain:"<strong>The tool generates plausible-sounding text from patterns and can fill gaps with made-up details</strong> accurately and accessibly explains why fabricated content appears.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool intentionally lies to deceive the board</b>: the model has no intent to deceive; errors stem from how it generates text.</span><span class='qd'><b>The tool has emotions that cause it to err</b>: AI has no emotions driving mistakes.</span><span class='qd'><b>The tool is broken and should never be used</b>: hallucinations are a known limitation, not proof the tool is unusable.</span>" },
{ id:"D6-094", domain:6, obj:"6.5", diff:"medium", q:"Which describes a healthy way to think about prompter, verifier, and editor roles?", options:["They are competing roles where only one can be right","They make human judgment unnecessary","They apply only to software engineers","They are complementary functions that together produce reliable AI-assisted work"], answer:3, explain:"<strong>They are complementary functions that together produce reliable AI-assisted work</strong> reflects how the roles reinforce one another across the workflow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are competing roles where only one can be right</b>: the roles cooperate rather than compete.</span><span class='qd'><b>They make human judgment unnecessary</b>: each role depends on human judgment.</span><span class='qd'><b>They apply only to software engineers</b>: these roles apply across many fields, not just engineering.</span>" },
{ id:"D6-095", domain:6, obj:"6.5", diff:"easy", q:"A colleague new to AI asks what a prompt is. Which plain explanation is BEST?", options:["A type of computer virus","The instruction or question you give the AI to get a response","The AI's internal wiring","A password for the AI account"], answer:1, explain:"<strong>The instruction or question you give the AI to get a response</strong> is a clear, correct definition of a prompt for a beginner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A type of computer virus</b>: a prompt is an instruction, not malware.</span><span class='qd'><b>The AI's internal wiring</b>: a prompt is input from the user, not the model's internals.</span><span class='qd'><b>A password for the AI account</b>: a prompt is not a credential.</span>" },
{ id:"D6-096", domain:6, obj:"6.6", diff:"medium", q:"How is AI MOST likely to reshape many jobs, according to current understanding?", options:["By instantly eliminating the need for any human worker","By changing which tasks people do and raising the value of oversight and judgment","By making all jobs identical","By removing the need for people to learn anything new"], answer:1, explain:"<strong>By changing which tasks people do and raising the value of oversight and judgment</strong> reflects the common view that AI shifts task mixes rather than simply erasing work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By instantly eliminating the need for any human worker</b>: AI augments many roles rather than instantly removing all workers.</span><span class='qd'><b>By making all jobs identical</b>: AI does not homogenize every job into one.</span><span class='qd'><b>By removing the need for people to learn anything new</b>: adapting to AI usually increases the need to learn.</span>" },
{ id:"D6-097", domain:6, obj:"6.6", diff:"medium", q:"For someone preparing their career for an AI-influenced future, which mindset is MOST useful?", options:["Assume your current skills will never need to change","Avoid all AI tools to stay safe","Stay adaptable and keep building skills AI complements, like judgment and communication","Rely on AI to make every decision for you"], answer:2, explain:"<strong>Stay adaptable and keep building skills AI complements, like judgment and communication</strong> is the most resilient career mindset in an AI-shaped workplace.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume your current skills will never need to change</b>: assuming no change leaves someone unprepared.</span><span class='qd'><b>Avoid all AI tools to stay safe</b>: avoiding AI entirely can reduce competitiveness.</span><span class='qd'><b>Rely on AI to make every decision for you</b>: over-reliance surrenders the judgment that stays valuable.</span>" },
{ id:"D6-098", domain:6, obj:"6.6", diff:"hard", q:"An employee worries AI will make their role obsolete. Which response reflects the MOST balanced, ethical career advice?", options:["Ignore AI entirely and hope it goes away","Sabotage AI projects to protect the role","Assume the role is already gone and stop trying","Learn to use AI to handle routine parts of the job while developing higher-value skills"], answer:3, explain:"<strong>Learn to use AI to handle routine parts of the job while developing higher-value skills</strong> is constructive and realistic, turning a threat into an opportunity to grow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore AI entirely and hope it goes away</b>: ignoring change does not prepare the employee.</span><span class='qd'><b>Sabotage AI projects to protect the role</b>: sabotage is unethical and harms the organization.</span><span class='qd'><b>Assume the role is already gone and stop trying</b>: giving up forecloses adaptation and growth.</span>" },
{ id:"D6-099", domain:6, obj:"6.6", diff:"medium", q:"Which is an ETHICAL consideration when a company adopts AI that affects employees' work?", options:["Hiding all AI plans from employees indefinitely","Maximizing profit regardless of the impact on people","Being transparent with staff and supporting reskilling where roles change","Replacing staff overnight with no communication"], answer:2, explain:"<strong>Being transparent with staff and supporting reskilling where roles change</strong> is an ethical approach that respects employees affected by AI adoption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hiding all AI plans from employees indefinitely</b>: concealment erodes trust and treats staff unfairly.</span><span class='qd'><b>Maximizing profit regardless of the impact on people</b>: ignoring human impact is not an ethical stance.</span><span class='qd'><b>Replacing staff overnight with no communication</b>: abrupt replacement without communication disregards employee welfare.</span>" },
{ id:"D6-100", domain:6, obj:"6.6", diff:"hard", q:"A worker wants to \"AI-proof\" their career as much as possible. Which strategy is MOST sound?", options:["Combine AI fluency with uniquely human strengths like ethics, judgment, and relationships","Memorize one AI tool's menus and never learn anything else","Refuse to disclose or discuss AI at work","Depend entirely on AI so no personal skills are needed"], answer:0, explain:"<strong>Combine AI fluency with uniquely human strengths like ethics, judgment, and relationships</strong> is the soundest strategy, pairing tool skill with capabilities AI complements rather than replaces.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Memorize one AI tool's menus and never learn anything else</b>: narrow memorization does not build durable, transferable value.</span><span class='qd'><b>Refuse to disclose or discuss AI at work</b>: avoiding discussion limits growth and transparency.</span><span class='qd'><b>Depend entirely on AI so no personal skills are needed</b>: total dependence weakens the human skills that remain valuable.</span>" }
);
